<svg viewBox="0 0 700 640" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Serie B1 de Flex -- La valoración se duplica en siete meses</text>
  <g font-family="sans-serif">
    <text x="20" y="60" fill="#a1a1aa" font-size="13">1. Cronología de financiación</text>
    <rect x="20" y="73" width="320" height="56" rx="8" fill="#f59e0b" opacity="0.85"/>
    <text x="180" y="98" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">Dic 2025: Serie B</text>
    <text x="180" y="118" fill="#111113" font-size="12" text-anchor="middle">70M$, valoración ~600M$</text>
    <rect x="360" y="73" width="320" height="56" rx="8" fill="#fbbf24" opacity="0.95"/>
